UPDATE character_races SET name = 'Human', slug = 'human', description = 'Adaptable people with broad talent and determination.', source_type = 'SYSTEM', source_name = 'Player''s Handbook 2024', active = true, creature_type = 'HUMANOID', size_options_json = '["SMALL","MEDIUM"]', default_size = 'MEDIUM', speed_json = '{"walk":30}', darkvision_range = null, traits_json = '[{"name":"Resourceful","description":"Gains a flexible heroic benefit."},{"name":"Skillful","description":"Gains additional training."},{"name":"Versatile","description":"Designed for broad character concepts."}]', lineages_json = '[]', lineage_required = false, allow_ability_score_bonuses = false, ability_score_bonuses_json = '[]' WHERE id = 'c0000000-0000-0000-0000-000000000001';
UPDATE character_races SET name = 'Elf', slug = 'elf', description = 'Fey-touched people known for keen senses and trance.', source_type = 'SYSTEM', source_name = 'Player''s Handbook 2024', active = true, creature_type = 'HUMANOID', size_options_json = '["MEDIUM"]', default_size = 'MEDIUM', speed_json = '{"walk":30}', darkvision_range = 60, traits_json = '[{"name":"Darkvision","description":"Sees in darkness within a limited range."},{"name":"Fey Ancestry","description":"Resists certain fey-related mental effects."},{"name":"Keen Senses","description":"Has heightened perception."},{"name":"Trance","description":"Rests through meditative trance."},{"name":"Elven Lineage","description":"Chooses a lineage with additional traits."}]', lineages_json = '[{"id":"10000000-0000-0000-0000-000000000201","name":"Drow","description":"Underdark lineage with shadow-themed magic."},{"id":"10000000-0000-0000-0000-000000000202","name":"High Elf","description":"Arcane lineage with minor magic."},{"id":"10000000-0000-0000-0000-000000000203","name":"Wood Elf","description":"Woodland lineage with mobility and nature themes."}]', lineage_required = true, allow_ability_score_bonuses = false, ability_score_bonuses_json = '[]' WHERE id = 'c0000000-0000-0000-0000-000000000002';
