UPDATE character_races SET name = 'Halfling', slug = 'halfling', description = 'Small, nimble people known for luck and courage.', source_type = 'SYSTEM', source_name = 'Player''s Handbook 2024', active = true, creature_type = 'HUMANOID', size_options_json = '["SMALL"]', default_size = 'SMALL', speed_json = '{"walk":30}', traits_json = '[{"name":"Brave","description":"Resists fear."},{"name":"Halfling Nimbleness","description":"Moves easily through larger creatures."},{"name":"Luck","description":"Can turn a poor roll into another chance."},{"name":"Naturally Stealthy","description":"Has a knack for hiding."}]', lineages_json = '[]', lineage_required = false, allow_ability_score_bonuses = false, ability_score_bonuses_json = '[]' WHERE id = 'c0000000-0000-0000-0000-000000000004';
