 '[]' WHERE id = 'c0000000-0000-0000-0000-000000000008';
INSERT INTO character_races (id, name, slug, description, source_type, source_name, active, creature_type, size_options_json, default_size, speed_json, darkvision_range, traits_json, lineages_json, lineage_required, allow_ability_score_bonuses, ability_score_bonuses_json) VALUES ('c0000000-0000-0000-0000-000000000009', 'Aasimar', 'aasimar', 'Celestial-touched humanoids with radiant gifts.', 'SYSTEM', 'Player''s Handbook 2024', true, 'HUMANOID', '["SMALL","MEDIUM"]', 'MEDIUM', '{"walk":30}', 60, '[{"name":"Celestial Resistance","description":"Resists radiant and necrotic harm."},{"name":"Darkvision","description":"Sees in darkness within a limited range."},{"name":"Healing Hands","description":"Can restore a small amount of vitality."},{"name":"Light Bearer","description":"Knows a light-themed magical effect."},{"name":"Celestial Revelation","description":"Reveals a temporary celestial aspect."}]', '[]', false, false, '[]'), ('c0000000-0000-0000-0000-000000000010', 'Goliath', 'goliath', 'Powerful folk tied to giant ancestry.', 'SYSTEM', 'Player''s Handbook 2024', true, 'HUMANOID', '["MEDIUM"]', 'MEDIUM', '{"walk":35}', null, '[{"name":"Giant Ancestry","description":"Chooses a giant ancestry benefit."},{"name":"Large Form","description":"Can briefly become larger."},{"name":"Powerful Build","description":"Counts as larger for carrying and moving weight."}]', '[{"id":"10000000-0000-0000-0000-000000001001","name":"Cloud Giant Ancestry","description":"Cloud-themed mobility or misdirection."},{"id":"10000000-0000-0000-0000-000000001002","name":"Fire Giant Ancestry","description":"Fire-themed endurance or offense."},{"id":"10000000-0000-0000-0000-000000001003","name":"Frost Giant Ancestry","description":"Cold-themed resilience."},{"id":"10000000-0000-0000-0000-000000001004","name":"Hill Giant Ancestry","description":"Endurance and impact theme."},{"id":"10000000-0000-0000-0000-000000001005","name":"Stone Giant Ancestry","description":"Stone-themed toughness."},{"id":"10000000-0000-0000-0000-000000001006","name":"Storm Giant Ancestry","description":"Storm-themed reaction or force."}]', true, false, '[]'), ('c0000000-0000-0000-0000-000000000011', 'Orc', 'orc', 'Strong and relentless humanoids with powerful endurance.', 'SYSTEM', 'Player''s Handbook 2024', true, 'HUMANOID', '["MEDIUM"]', 'MEDIUM', '{"walk":30}', 120, '[{"name":"Adrenaline Rush","description":"Can surge into movement and toughness."},{"name":"Darkvision","description":"Sees in darkness within a long range."},{"name":"Relentless Endurance","description":"Can stay standing when a blow would drop them."}]', '[]', false, false, '[]') ON CONFLICT (id) DO NOTHING;
